import React from 'react';
import {
  AbsoluteFill,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from 'remotion';

const Caption: React.FC<{ text: string; startFrame: number; endFrame: number }> = ({
  text,
  startFrame,
  endFrame,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  if (frame < startFrame || frame >= endFrame) return null;

  const progress = spring({
    frame: frame - startFrame,
    fps,
    config: { damping: 12, stiffness: 200, mass: 0.5 },
  });

  const scale = interpolate(progress, [0, 1], [0.5, 1]);
  const opacity = interpolate(progress, [0, 1], [0, 1]);

  return (
    <div
      style={{
        position: 'absolute',
        bottom: 200,
        width: '100%',
        textAlign: 'center',
        transform: `scale(${scale})`,
        opacity,
      }}
    >
      <span
        style={{
          fontSize: 96,
          fontWeight: 700,
          color: '#ffffff',
          fontFamily: 'sans-serif',
          textShadow: '0 4px 24px rgba(0,0,0,0.6)',
        }}
      >
        {text}
      </span>
    </div>
  );
};

export const HelloVideo: React.FC = () => {
  const frame = useCurrentFrame();

  const titleOpacity = interpolate(frame, [0, 30], [0, 1], {
    extrapolateRight: 'clamp',
  });

  return (
    <AbsoluteFill
      style={{
        backgroundColor: '#1a1a2e',
        justifyContent: 'center',
        alignItems: 'center',
      }}
    >
      <div
        style={{
          opacity: titleOpacity,
          fontSize: 144,
          fontWeight: 900,
          color: '#e0e0ff',
          fontFamily: 'sans-serif',
          letterSpacing: 8,
          textShadow: '0 0 60px rgba(120,80,255,0.8)',
        }}
      >
        Hello
      </div>

      <Caption text="one" startFrame={120} endFrame={180} />
      <Caption text="two" startFrame={180} endFrame={240} />
      <Caption text="three" startFrame={240} endFrame={300} />
    </AbsoluteFill>
  );
};

